def perform_majority_voting(image_id: str) -> Optional[AggregationResult]:
    """Aggregate labels for an image using majority voting."""
    if image_id not in annotations_store:
        return None

    votes = annotations_store[image_id]
    if len(votes) < MIN_ANNOTATORS:
        return None

    labels = list(votes.values())
    counter = Counter(labels)
    total_votes = len(labels)

    most_common_label, most_common_count = counter.most_common(1)[0]
    confidence = most_common_count / total_votes

    result = AggregationResult(
        image_id=image_id,
        aggregated_label=most_common_label,
        confidence=confidence,
        vote_counts=dict(counter),
        total_votes=total_votes
    )

    aggregated_labels[image_id] = {
        "label": most_common_label,
        "confidence": confidence,
        "vote_counts": dict(counter)
    }

    return result


def aggregate_all_labels():
    """Re-aggregate labels for all images."""
    for image_id in annotations_store:
        perform_majority_voting(image_id)


