@app.post("/images/upload", tags=["Images"])
async def upload_image(file: UploadFile = File(...)):
    """Upload an image for labeling."""
    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image")

    image_id = str(uuid.uuid4())
    image_data = await file.read()

    # Validate it's a real image
    if HAS_ML:
        try:
            Image.open(BytesIO(image_data))
        except Exception:
            raise HTTPException(status_code=400, detail="Invalid image file")

    image_store[image_id] = {
        "filename": file.filename,
        "data": image_data
    }
    annotations_store[image_id] = {}

    return {
        "image_id": image_id,
        "filename": file.filename,
        "size_bytes": len(image_data),
        "message": "Image uploaded successfully"
    }


@app.post("/images/upload-base64", tags=["Images"])
async def upload_image_base64(image_id: Optional[str] = None,
                               filename: str = "image.jpg",
                               image_base64: str = ""):
    """Upload an image as base64 string."""
    if not image_base64:
        raise HTTPException(status_code=400, detail="image_base64 is required")

    try:
        image_data = base64.b64decode(image_base64)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid base64 data")

    if not image_id:
        image_id = str(uuid.uuid4())

    image_store[image_id] = {
        "filename": filename,
        "data": image_data
    }
    if image_id not in annotations_store:
        annotations_store[image_id] = {}

    return {
        "image_id": image_id,
        "filename": filename,
        "size_bytes": len(image_data),
        "message": "Image uploaded successfully"
    }


