@app.post("/annotations", response_model=AnnotationResponse, tags=["Annotations"])
async def submit_annotation(annotation: AnnotationRequest):
    """Submit a label annotation for an image from an annotator."""
    if annotation.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found. Upload the image first.")

    image_id = annotation.image_id
    annotator_id = annotation.annotator_id
    label = annotation.label.strip().lower()

    if not label:
        raise HTTPException(status_code=400, detail="Label cannot be empty")

    # Store the annotation
    if image_id not in annotations_store:
        annotations_store[image_id] = {}

    old_label = annotations_store[image_id].get(annotator_id)
    annotations_store[image_id][annotator_id] = label
    label_classes.add(label)

    # Auto-aggregate if enough annotations
    total_annotations = len(annotations_store[image_id])
    if total_annotations >= MIN_ANNOTATORS:
        perform_majority_voting(image_id)

    message = f"Annotation submitted successfully"
    if old_label:
        message += f" (updated from '{old_label}' to '{label}')"

    return AnnotationResponse(
        image_id=image_id,
        annotator_id=annotator_id,
        label=label,
        total_annotations=total_annotations,
        message=message
    )


@app.post("/annotations/bulk", tags=["Annotations"])
async def submit_bulk_annotations(annotations: list[AnnotationRequest]):
    """Submit multiple annotations at once."""
    results = []
    errors = []

    for ann in annotations:
        try:
            if ann.image_id not in image_store:
                errors.append({"image_id": ann.image_id, "error": "Image not found"})
                continue

            label = ann.label.strip().lower()
            if not label:
                errors.append({"image_id": ann.image_id, "error": "Empty label"})
                continue

            if ann.image_id not in annotations_store:
                annotations_store[ann.image_id] = {}

            annotations_store[ann.image_id][ann.annotator_id] = label
            label_classes.add(label)

            if len(annotations_store[ann.image_id]) >= MIN_ANNOTATORS:
                perform_majority_voting(ann.image_id)

            results.append({
                "image_id": ann.image_id,
                "annotator_id": ann.annotator_id,
                "label": label,
                "status": "success"
            })
        except Exception as e:
            errors.append({"image_id": ann.image_id, "error": str(e)})

    return {
        "submitted": len(results),
        "errors": len(errors),
        "results": results,
        "error_details": errors
    }


